def analyze_election_results(election_data):
    """
    Analyzes election results for the Leederville seat and returns total votes per party.

    Args:
        election_data (dict): A dictionary where keys are election years and values are
                            dictionaries of party names mapped to votes.
                            Example: {1911: {'Labor': 5000, 'Liberal': 4500}}

    Returns:
        dict: Total votes per party across all elections.
    """
    total_votes = {}
    for year, results in election_data.items():
        for party, votes in results.items():
            total_votes[party] = total_votes.get(party, 0) + votes
    return total_votes

# Example usage:
election_data = {
    1911: {'Labor': 5000, 'Liberal': 4500},
    1914: {'Labor': 4800, 'Liberal': 4881},
    1930: {'Labor': 5200, 'Nationalist': 4900}
}
print(analyze_election_results(election_data))
# Output: {'Labor': 15000, 'Liberal': 9381, 'Nationalist': 4900}
